import { mergeDateIntoReferenceDate } from '/workspace/mui-x/packages/x-date-pickers/src/internals/hooks/useField/useField.utils';
import type { FieldSection } from '/workspace/mui-x/packages/x-date-pickers/src/models/fields';

const adapter = new AdapterDateFns();

const meridiemSection: FieldSection = {
  value: 'AM',
  format: 'aa',
  maxLength: null,
  placeholder: 'aa',
  type: 'meridiem',
  contentType: 'letter',
  hasLeadingZerosInFormat: false,
  hasLeadingZerosInInput: false,
  modified: true,
  startSeparator: ' ',
  endSeparator: '',
};

function runCase(label: string, referenceHour: number, transferFromHour: number, expectedHour: number) {
  const referenceDate = new Date(2026, 2, 8, referenceHour, 30, 15, 0);
  const parsedEditedDate = new Date(2026, 2, 8, transferFromHour, 0, 0, 0);
  const mergedDate = mergeDateIntoReferenceDate(
    adapter,
    parsedEditedDate,
    [meridiemSection],
    referenceDate,
    true,
  );
  const actual = {
    year: mergedDate.getFullYear(),
    month: mergedDate.getMonth() + 1,
    date: mergedDate.getDate(),
    hours: mergedDate.getHours(),
    minutes: mergedDate.getMinutes(),
    seconds: mergedDate.getSeconds(),
  };
  console.log(label, mergedDate.toString(), actual);
  if (
    actual.year !== 2026 ||
    actual.month !== 3 ||
    actual.date !== 8 ||
    actual.hours !== expectedHour ||
    actual.minutes !== 30 ||
    actual.seconds !== 15
  ) {
    throw new Error(`${label}: expected March 8, 2026 ${expectedHour}:30:15, got ${JSON.stringify(actual)}`);
  }
}

